// ===== EDIT YOUR SETTINGS HERE =====
// Defaults below match the Gumroad + n8n Creator listings.
// Change only what you need; leave unused destinations as placeholders.

// Where to log admin tasks:
//   'sheets'   -> Google Sheets only
//   'airtable' -> Airtable only
//   'both'     -> Google Sheets and Airtable
const TASK_LOG = 'sheets';

const GOOGLE_SHEET_ID = 'your-google-sheet-id';
const SHEETS_TAB_NAME = 'Admin Tasks';

const AIRTABLE_BASE_ID = 'appXXXXXXXXXXXXXX';
const ADMIN_TASKS_TABLE_NAME = 'Admin Tasks';

// Where to send alerts for urgent, due-soon, or review-needed admin items:
//   'slack' -> Slack only
//   'teams' -> Microsoft Teams only
//   'both'  -> Slack and Teams
//   'none'  -> no chat alerts
const NOTIFY_CHANNELS = 'slack';
const SLACK_CHANNEL = '#admin-tasks';
const TEAMS_WEBHOOK_URL = 'https://outlook.office.com/webhook/your-teams-incoming-webhook';

const URGENT_DUE_DAYS = 3;
const DUPLICATE_WINDOW_DAYS = 30;
const ALERT_REVIEW_ITEMS = true;
const REDACT_BEFORE_AI = true;
const DEFAULT_SOURCE = 'gmail_admin';

const payload = $input.first().json;
const taskLog = String(TASK_LOG || 'sheets').toLowerCase().trim();
const notifyChannels = String(NOTIFY_CHANNELS || 'slack').toLowerCase().trim();

return [
  {
    json: {
      taskLog,
      useSheetsLog: taskLog === 'sheets' || taskLog === 'both',
      useAirtableLog: taskLog === 'airtable' || taskLog === 'both',
      googleSheetId: GOOGLE_SHEET_ID,
      sheetsTabName: SHEETS_TAB_NAME,
      airtableBaseId: AIRTABLE_BASE_ID,
      adminTasksTableName: ADMIN_TASKS_TABLE_NAME,
      notifyChannels,
      useSlack: notifyChannels === 'slack' || notifyChannels === 'both',
      useTeams: notifyChannels === 'teams' || notifyChannels === 'both',
      slackChannel: SLACK_CHANNEL,
      teamsWebhookUrl: TEAMS_WEBHOOK_URL,
      urgentDueDays: URGENT_DUE_DAYS,
      duplicateWindowDays: DUPLICATE_WINDOW_DAYS,
      alertReviewItems: ALERT_REVIEW_ITEMS,
      redactBeforeAi: REDACT_BEFORE_AI,
      defaultSource: DEFAULT_SOURCE,
      payload,
    },
  },
];

const settings = $input.first().json;
const raw = settings.payload || {};

const htmlToText = (value) => String(value || '')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+\n/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

const redact = (value) => {
  let text = String(value || '');
  text = text.replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED_SSN]');
  text = text.replace(/\b(?:\d[ -]*?){13,19}\b/g, (match) => {
    const digits = match.replace(/\D/g, '');
    return digits.length >= 13 ? `[REDACTED_NUMBER_ENDING_${digits.slice(-4)}]` : match;
  });
  text = text.replace(/\b(?:\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, '[REDACTED_PHONE]');
  text = text.replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, '[REDACTED_EMAIL]');
  text = text.replace(/\b\d{1,6}\s+[A-Za-z0-9.'-]+\s+(?:Street|St|Avenue|Ave|Road|Rd|Drive|Dr|Lane|Ln|Boulevard|Blvd|Court|Ct|Way|Place|Pl)\b/gi, '[REDACTED_ADDRESS]');
  text = text.replace(/\b(?:account|acct|policy|member|case|claim|confirmation|reservation|invoice)\s*(?:number|#|id)?\s*[:#]?\s*[A-Z0-9-]{4,}\b/gi, (match) => {
    const id = match.match(/[A-Z0-9-]{4,}$/i)?.[0] || '';
    return `${match.split(':')[0].split('#')[0].trim()} [REDACTED_ID_ENDING_${id.slice(-4)}]`;
  });
  return text;
};

const headers = raw.headers || raw.payload?.headers || {};
const subject = raw.subject || raw.Subject || headers.subject || raw.payload?.subject || '';
const fromEmail = raw.from || raw.From || headers.from || raw.payload?.from || '';
const messageId = raw.id || raw.messageId || raw.message_id || raw.payload?.id || `admin-${Date.now()}`;
const receivedAt = raw.date || raw.internalDate || raw.receivedAt || new Date().toISOString();
const textBody = raw.textPlain || raw.text || raw.snippet || raw.body?.text || '';
const htmlBody = raw.textHtml || raw.html || raw.body?.html || '';
const rawText = htmlToText(textBody || htmlBody || raw.snippet || JSON.stringify(raw).slice(0, 6000));
const redactedText = settings.redactBeforeAi ? redact(rawText) : rawText;
const compact = rawText.toLowerCase().replace(/\s+/g, ' ').replace(/'/g, '').slice(0, 1000);
const adminHash = `${fromEmail}|${subject}|${compact}`.toLowerCase();

return [
  {
    json: {
      ...settings,
      messageId: String(messageId),
      receivedAt,
      source: raw.source || settings.defaultSource || 'gmail_admin',
      originalSubject: String(subject),
      fromEmail: String(fromEmail),
      rawText: rawText.slice(0, 10000),
      redactedText: redactedText.slice(0, 10000),
      rawTextSnippet: rawText.slice(0, 1000),
      adminHash,
      redactionApplied: rawText !== redactedText,
      _mockExistingTasks: Array.isArray(raw._mockExistingTasks) ? raw._mockExistingTasks : [],
      _testScenario: raw._testScenario || raw.scenario || '',
    },
  },
];

const admin = $('Redact Email Content').first().json;
const rows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);
return [{ json: { ...admin, _lookupRows: rows } }];

function fromNode(name) {
  try {
    return $(name).first().json;
  } catch (error) {
    return null;
  }
}

const prev =
  fromNode('Compile Airtable Data') ||
  fromNode('Skip Airtable Data Usage') ||
  $('Redact Email Content').first().json;

const sheetRows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);

return [{ json: { ...prev, _lookupRows: [...(prev._lookupRows || []), ...sheetRows] } }];

const admin = $input.first().json;
const rows = Array.isArray(admin._lookupRows) ? admin._lookupRows : [];
const windowDays = admin.duplicateWindowDays ?? 30;
const cutoff = Date.now() - windowDays * 24 * 60 * 60 * 1000;

const isDuplicate = rows.some((row) => {
  const record = row.fields || row;
  if (record._mockEmpty) return false;
  const existingMessageId = String(record['Message ID'] || record.messageId || '').trim();
  const existingHash = String(record['Admin Hash'] || record.adminHash || '').toLowerCase();
  const existingAt = Date.parse(record['Received At'] || record.receivedAt || record.createdTime || '');

  if (admin.messageId && existingMessageId && admin.messageId === existingMessageId) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  if (admin.adminHash && existingHash && admin.adminHash === existingHash) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  return false;
});

return [{ json: { ...admin, isDuplicate } }];

const item = $input.first().json;
return [
  {
    json: {
      status: 'skipped',
      reason: item.isDuplicate ? 'duplicate_admin_item' : 'filtered',
      messageId: item.messageId,
      adminHash: item.adminHash,
      testScenario: item._testScenario || '',
    },
  },
];

