const admin = $('Detect Email Duplication').first().json;
const aiItem = $input.first().json;
const raw =
  aiItem.message?.content ||
  aiItem.content ||
  aiItem.text ||
  aiItem.output ||
  aiItem.output_text ||
  aiItem.choices?.[0]?.message?.content ||
  '';

let extraction = {
  isAdminItem: true,
  extractionStatus: 'extracted',
  failureReason: '',
  category: 'General admin',
  priority: 'medium',
  dueDate: '',
  dueTime: '',
  organization: '',
  actionRequired: true,
  taskTitle: '',
  summary: '',
  recommendedNextStep: '',
  amount: '',
  accountLastFour: '',
  url: '',
  confidence: 50,
  needsReview: true,
  notes: '',
};

let parsedOk = false;
try {
  const jsonMatch = String(raw).match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    extraction = { ...extraction, ...JSON.parse(jsonMatch[0]) };
    parsedOk = true;
  }
} catch (error) {
  extraction.extractionStatus = 'failed';
  extraction.failureReason = 'OpenAI returned text that was not valid admin JSON';
}

if (!parsedOk && !extraction.failureReason) {
  extraction.extractionStatus = 'failed';
  extraction.failureReason = 'OpenAI did not return a JSON object';
}

const confidence = Math.max(0, Math.min(100, Number(extraction.confidence) || 50));
const priority = String(extraction.priority || 'medium').toLowerCase();
const dueDateValue = String(extraction.dueDate || '');
const dueTimeValue = String(extraction.dueTime || '');
const dueAt = Date.parse(dueDateValue);
const dueSoon = Number.isFinite(dueAt)
  ? dueAt <= Date.now() + (admin.urgentDueDays ?? 3) * 24 * 60 * 60 * 1000
  : false;
const isAdminItem = extraction.isAdminItem !== false && extraction.extractionStatus !== 'not_admin';
const needsReview = Boolean(extraction.needsReview || confidence < 70 || (!extraction.taskTitle && !extraction.summary));
const extractionFailed = Boolean(aiItem.error || extraction.extractionStatus === 'failed' || !parsedOk);
const extractionSucceeded = Boolean(isAdminItem && !extractionFailed);

let route = 'standard';
if (!isAdminItem) route = 'not_admin';
else if (extractionFailed) route = 'extraction_failed';
else if (needsReview) route = 'review';
else if (priority === 'urgent' || priority === 'high') route = 'priority';
else if (dueSoon) route = 'due_soon';

const shouldAlert = Boolean(
  admin.notifyChannels !== 'none' &&
    extractionSucceeded &&
    (priority === 'urgent' ||
      priority === 'high' ||
      dueSoon ||
      (admin.alertReviewItems && needsReview))
);

return [
  {
    json: {
      ...admin,
      category: String(extraction.category || 'General admin'),
      priority,
      dueDate: dueDateValue,
      dueTime: dueTimeValue,
      dueSoon,
      organization: String(extraction.organization || ''),
      actionRequired: Boolean(extraction.actionRequired),
      taskTitle: String(extraction.taskTitle || extraction.summary || 'Admin item needs review'),
      summary: String(extraction.summary || ''),
      recommendedNextStep: String(extraction.recommendedNextStep || ''),
      amount: String(extraction.amount || ''),
      accountLastFour: String(extraction.accountLastFour || ''),
      url: String(extraction.url || ''),
      isAdminItem,
      extractionStatus: extractionFailed ? 'failed' : isAdminItem ? 'extracted' : 'not_admin',
      extractionSucceeded,
      extractionFailureReason:
        aiItem.error?.message ||
        extraction.failureReason ||
        (!isAdminItem ? 'Email does not appear to be an admin task, reminder, bill, renewal, appointment, travel item, or deadline' : ''),
      confidence,
      needsReview,
      shouldAlert,
      route,
      notes: String(extraction.notes || ''),
    },
  },
];

const item = $input.first().json;
const reason = item.isAdminItem === false ? 'non_admin_email' : 'extraction_failed';

return [
  {
    json: {
      status: 'skipped',
      reason,
      message:
        reason === 'non_admin_email'
          ? 'Email was processed successfully but does not appear to be an admin task.'
          : 'Admin task extraction failed. Check the email content or OpenAI node output.',
      messageId: item.messageId,
      adminHash: item.adminHash,
      extractionStatus: item.extractionStatus,
      extractionFailureReason: item.extractionFailureReason || '',
      originalSubject: item.originalSubject,
      fromEmail: item.fromEmail,
      testScenario: item._testScenario || '',
    },
  },
];

const item = $input.first().json;
const reason =
  item.route === 'review'
    ? 'Needs review'
    : item.route === 'priority'
      ? 'Priority admin item'
      : item.route === 'due_soon'
        ? 'Due soon'
        : 'Admin item logged';

const details = [
  `Reason: ${reason}`,
  `Task: ${item.taskTitle}`,
  `Category: ${item.category}`,
  `Priority: ${item.priority}`,
  item.dueDate ? `Due: ${item.dueDate}${item.dueTime ? ` ${item.dueTime}` : ''}` : '',
  item.organization ? `Organization: ${item.organization}` : '',
  item.amount ? `Amount: ${item.amount}` : '',
  `Confidence: ${item.confidence}/100`,
  `Subject: ${item.originalSubject}`,
].filter(Boolean);

const slackMessage = [`*${reason}: ${item.taskTitle}*`, '', ...details.map((line) => `- ${line}`)].join('\n');
const teamsMessage = [`**${reason}: ${item.taskTitle}**`, '', ...details.map((line) => `- ${line}`)].join('\n');

return [
  {
    json: {
      ...item,
      useSlackAlert: Boolean(item.shouldAlert && item.useSlack),
      useTeamsAlert: Boolean(item.shouldAlert && item.useTeams),
      slackMessage,
      teamsMessage,
    },
  },
];

const item = $input.first().json;
return [
  {
    json: {
      status: 'ok',
      taskLog: item.taskLog,
      sheetsLogged: item.sheetsLogged || 'no',
      airtableLogged: item.airtableLogged || 'no',
      taskTitle: item['Task Title'],
      category: item.Category,
      priority: item.Priority,
      dueDate: item['Due Date'],
      needsReview: item['Needs Review'],
      alertSent: item['Alert Sent'],
      redactionApplied: item['Redaction Applied'],
      testScenario: item._testScenario || '',
    },
  },
];
